const stocks = $input.all();
const orderData = $("Get the Product Id").all(); // For node '1', change this to "Get the Product Id2"

// 1. Create a lookup map of product_id -> quantity from the order
const quantityMap = {};
orderData.forEach(item => {
  const pid = item.json.product_id;
  const qty = parseFloat(item.json.quantity) || 0;
  quantityMap[pid] = qty;
});

// 2. Map through stocks and add the specific quantity for THAT product
return stocks.map(stock => {
  const productId = stock.json.product_id;
  const currentStock = parseFloat(stock.json.Stocks) || 0;
  const orderQty = quantityMap[productId] || 0;

  return {
    json: {
      ...stock.json,
      total: currentStock + orderQty
    }
  };
});

